import { VoronoiCanvas } from './voronoi-canvas';

export const metadata = { title: 'voronoi — incomplete.fun' };

export default function Page() {
  return <VoronoiCanvas />;
}

content.content:
1	'use client';
2	
3	import { useRef, useState, useEffect, useCallback } from 'react';
4	
5	type Metric = 'euclidean' | 'manhattan' | 'chebyshev' | 'minkowski3' | 'minkowski05';
6	
7	const METRICS: Metric[] = ['minkowski05', 'manhattan', 'euclidean', 'minkowski3', 'chebyshev'];
8	const METRIC_LABEL: Record<Metric, string> = {
9	  euclidean: 'L2', manhattan: 'L1', chebyshev: 'L∞', minkowski3: 'L3', minkowski05: 'L½',
10	};
11	const METRIC_DESC: Record<Metric, string> = {
12	  euclidean:   'euclidean (circular)',
13	  manhattan:   'manhattan (diamond)',
14	  chebyshev:   'chebyshev (square)',
15	  minkowski3:  'minkowski p=3 (rounded square)',
16	  minkowski05: 'minkowski p=½ (star)',
17	};
18	const METRIC_FORMULA: Record<Metric, string> = {
19	  euclidean:   'sqrt(dx² + dy²)',
20	  manhattan:   'dx + dy',
21	  chebyshev:   'max(dx, dy)',
22	  minkowski3:  '(dx³ + dy³)^(1/3)',
23	  minkowski05: '(sqrt(dx) + sqrt(dy))²',
24	};
25	const METRIC_GENERIC_CALC: Record<Metric, string> = {
26	  euclidean:   'sqrt(x² + y²)',
27	  manhattan:   'x + y',
28	  chebyshev:   'max(x, y)',
29	  minkowski3:  '(x³ + y³)^(1/3)',
30	  minkowski05: '(sqrt(x) + sqrt(y))²',
31	};
32	const METRIC_INDEX: Record<Metric, number> = {
33	  euclidean: 0, manhattan: 1, chebyshev: 2, minkowski3: 3, minkowski05: 4,
34	};
35	
36	interface Site {
37	  id: string;
38	  x: number; y: number;
39	  metric: Metric;
40	  r: number; g: number; b: number;
41	}
42	
43	function metricDistJS(m: Metric, ax: number, ay: number): number {
44	  switch (m) {
45	    case 'euclidean':   return Math.sqrt(ax * ax + ay * ay);
46	    case 'manhattan':   return ax + ay;
47	    case 'chebyshev':   return Math.max(ax, ay);
48	    case 'minkowski3':  return Math.cbrt(ax * ax * ax + ay * ay * ay);
49	    case 'minkowski05': { const s = Math.sqrt(ax) + Math.sqrt(ay); return s * s; }
50	  }
51	}
52	
53	function fmt(n: number): string {
54	  return Math.abs(n - Math.round(n)) < 0.05 ? String(Math.round(n)) : n.toFixed(1);
55	}
56	
57	function metricCalculation(m: Metric, dx: number, dy: number): string {
58	  const d = metricDistJS(m, dx, dy);
59	  const x = fmt(dx);
60	  const y = fmt(dy);
61	  const v = fmt(d);
62	  switch (m) {
63	    case 'euclidean':   return `sqrt(${x}² + ${y}²) = ${v}`;
64	    case 'manhattan':   return `${x} + ${y} = ${v}`;
65	    case 'chebyshev':   return `max(${x}, ${y}) = ${v}`;
66	    case 'minkowski3':  return `(${x}³ + ${y}³)^(1/3) = ${v}`;
67	    case 'minkowski05': return `(sqrt(${x}) + sqrt(${y}))² = ${v}`;
68	  }
69	}
70	
71	function hslToRgb(h: number, s: number, l: number): [number, number, number] {
72	  s /= 100; l /= 100;
73	  const k = (n: number) => (n + h / 30) % 12;
74	  const a = s * Math.min(l, 1 - l);
75	  const f = (n: number) => l - a * Math.max(-1, Math.min(k(n) - 3, Math.min(9 - k(n), 1)));
76	  return [Math.round(f(0) * 255), Math.round(f(8) * 255), Math.round(f(4) * 255)];
77	}
78	
79	// ── WebGL shaders ─────────────────────────────────────────────────────────────
80	
81	const VERT = `#version 300 es
82	in vec2 a_pos;
83	void main() { gl_Position = vec4(a_pos, 0.0, 1.0); }
84	`;
85	
86	// Fragment shader: per-pixel Voronoi with smooth anti-aliased borders.
87	// Each site has its own distance metric; boundaries are where two sites tie.
88	// The gap between d1 (nearest) and d2 (second-nearest) is 0 exactly on the
89	// boundary and grows away from it — used for smooth border darkening.
90	const FRAG = `#version 300 es
91	precision highp float;
92	
93	const int MAX = 64;
94	
95	uniform vec2  u_res;
96	uniform float u_dpr;
97	uniform int   u_n;
98	uniform vec2  u_sites[MAX];
99	uniform vec3  u_colors[MAX];
100	uniform int   u_metrics[MAX];
101	
102	out vec4 fragColor;
103	
104	float vdist(int m, float ax, float ay) {
105	  if (m == 0) return sqrt(ax*ax + ay*ay);
106	  if (m == 1) return ax + ay;
107	  if (m == 2) return max(ax, ay);
108	  if (m == 3) return pow(ax*ax*ax + ay*ay*ay, 1.0/3.0);
109	  float s = sqrt(ax) + sqrt(ay); return s*s;
110	}
111	
112	// Analytical gradient of the distance function w.r.t. (p - site).
113	// Returns the 2D gradient vector in physical-pixel space.
114	vec2 vdist_grad(int m, vec2 dp) {
115	  float ax = abs(dp.x), ay = abs(dp.y);
116	  float sx = sign(dp.x), sy = sign(dp.y);
117	  if (m == 0) {                        // L2
118	    float d = sqrt(ax*ax + ay*ay);
119	    return d < 1e-7 ? vec2(0.0) : dp / d;
120	  }
121	  if (m == 1) return vec2(sx, sy);     // L1
122	  if (m == 2) {                        // L∞
123	    if (ax > ay) return vec2(sx, 0.0);
124	    if (ay > ax) return vec2(0.0, sy);
125	    return vec2(sx, sy) * 0.5;
126	  }
127	  if (m == 3) {                        // L3
128	    float d3 = ax*ax*ax + ay*ay*ay;
129	    float d  = pow(d3, 1.0/3.0);
130	    return d < 1e-7 ? vec2(0.0) : vec2(sx*ax*ax, sy*ay*ay) / (d*d);
131	  }
132	  // L½
133	  float sax = sqrt(max(ax, 1e-7)), say = sqrt(max(ay, 1e-7));
134	  float sum = sqrt(ax) + sqrt(ay);
135	  return vec2(ax < 1e-7 ? 0.0 : sx * sum / sax,
136	              ay < 1e-7 ? 0.0 : sy * sum / say);
137	}
138	
139	void main() {
140	  if (u_n == 0) { fragColor = vec4(0.0); return; }
141	
142	  vec2 p = vec2(gl_FragCoord.x, u_res.y - gl_FragCoord.y);
143	
144	  float d1 = 1e9, d2 = 1e9;
145	  int owner = 0, owner2 = 0;
146	
147	  for (int i = 0; i < MAX; i++) {
148	    if (i >= u_n) break;
149	    float d = vdist(u_metrics[i], abs(p.x - u_sites[i].x), abs(p.y - u_sites[i].y));
150	    if (d < d1) { d2 = d1; owner2 = owner; d1 = d; owner = i; }
151	    else if (d < d2) { d2 = d; owner2 = i; }
152	  }
153	
154	  // Analytical gradient of gap = d2 - d1 avoids the dFdx/dFdy triple-point
155	  // artifact where adjacent fragments in a 2×2 quad use different site pairs,
156	  // causing the screen-space derivative to be computed from incompatible values.
157	  float gap = d2 - d1;
158	  vec2 g1 = vdist_grad(u_metrics[owner],  p - u_sites[owner]);
159	  vec2 g2 = vdist_grad(u_metrics[owner2], p - u_sites[owner2]);
160	  float grad = max(length(g2 - g1), 1e-4);
161	  float borderDist = gap / grad;
162	  float border = smoothstep(0.0, 1.5 * u_dpr, borderDist);
163	  fragColor = vec4(u_colors[owner] * mix(0.22, 1.0, border), 1.0);
164	}
165	`;
166	
167	function compileShader(gl: WebGL2RenderingContext, type: number, src: string) {
168	  const s = gl.createShader(type)!;
169	  gl.shaderSource(s, src); gl.compileShader(s);
170	  return s;
171	}
172	
173	let nextId = 0;
174	
175	export function VoronoiCanvas() {
176	  // Two stacked canvases: WebGL for Voronoi cells, 2D for site markers.
177	  const glCanvasRef     = useRef<HTMLCanvasElement>(null);
178	  const markerCanvasRef = useRef<HTMLCanvasElement>(null);
179	  const containerRef    = useRef<HTMLDivElement>(null);
180	
181	  // WebGL state
182	  const glRef   = useRef<WebGL2RenderingContext | null>(null);
183	  const progRef = useRef<WebGLProgram | null>(null);
184	  const uRef    = useRef<Record<string, WebGLUniformLocation | null>>({});
185	
186	  const sitesRef      = useRef<Site[]>([]);
187	  const selectedIdRef = useRef<string | null>(null);
188	
189	  const [sites, setSitesState]   = useState<Site[]>([]);
190	  const [selectedId, setSelectedId] = useState<string | null>(null);
191	  const [currentMetric, setCurrentMetric] = useState<Metric>('euclidean');
192	  const [mousePos, setMousePos] = useState<{ x: number; y: number } | null>(null);
193	  const [mouseOverCanvas, setMouseOverCanvas] = useState(false);
194	  const siteCount = useRef(0);
195	
196	  const dragRef = useRef<{
197	    id: string; startMouseX: number; startMouseY: number;
198	    origX: number; origY: number; moved: boolean;
199	  } | null>(null);
200	  const mouseDownOnSite = useRef(false);
201	
202	  const commitSites = useCallback((next: Site[]) => {
203	    sitesRef.current = next;
204	    setSitesState(next);
205	  }, []);
206	
207	  // ── WebGL init ──────────────────────────────────────────────────────────────
208	  useEffect(() => {
209	    const canvas = glCanvasRef.current;
210	    if (!canvas) return;
211	    const gl = canvas.getContext('webgl2', { alpha: true, premultipliedAlpha: false });
212	    if (!gl) return;
213	    glRef.current = gl;
214	
215	    const prog = gl.createProgram()!;
216	    gl.attachShader(prog, compileShader(gl, gl.VERTEX_SHADER, VERT));
217	    gl.attachShader(prog, compileShader(gl, gl.FRAGMENT_SHADER, FRAG));
218	    gl.linkProgram(prog);
219	    gl.useProgram(prog);
220	    progRef.current = prog;
221	
222	    // Fullscreen quad (two triangles)
223	    const buf = gl.createBuffer();
224	    gl.bindBuffer(gl.ARRAY_BUFFER, buf);
225	    gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([
226	      -1, -1,  1, -1,  -1,  1,
227	      -1,  1,  1, -1,   1,  1,
228	    ]), gl.STATIC_DRAW);
229	    const loc = gl.getAttribLocation(prog, 'a_pos');
230	    gl.enableVertexAttribArray(loc);
231	    gl.vertexAttribPointer(loc, 2, gl.FLOAT, false, 0, 0);
232	
233	    uRef.current = {
234	      res:     gl.getUniformLocation(prog, 'u_res'),
235	      dpr:     gl.getUniformLocation(prog, 'u_dpr'),
236	      n:       gl.getUniformLocation(prog, 'u_n'),
237	      sites:   gl.getUniformLocation(prog, 'u_sites'),
238	      colors:  gl.getUniformLocation(prog, 'u_colors'),
239	      metrics: gl.getUniformLocation(prog, 'u_metrics'),
240	    };
241	  }, []);
242	
243	  // ── Render ──────────────────────────────────────────────────────────────────
244	  const renderGL = useCallback(() => {
245	    const gl   = glRef.current;
246	    const prog = progRef.current;
247	    const u    = uRef.current;
248	    const canvas = glCanvasRef.current;
249	    if (!gl || !prog || !canvas) return;
250	
251	    const dpr   = window.devicePixelRatio || 1;
252	    const sites = sitesRef.current;
253	
254	    gl.viewport(0, 0, canvas.width, canvas.height);
255	    gl.uniform2f(u.res, canvas.width, canvas.height);
256	    gl.uniform1f(u.dpr, dpr);
257	    gl.uniform1i(u.n, sites.length);
258	
259	    if (sites.length > 0) {
260	      const sv = new Float32Array(sites.length * 2);
261	      const cv = new Float32Array(sites.length * 3);
262	      const mv = new Int32Array(sites.length);
263	      for (let i = 0; i < sites.length; i++) {
264	        sv[i * 2]     = sites[i].x * dpr;
265	        sv[i * 2 + 1] = sites[i].y * dpr;
266	        cv[i * 3]     = sites[i].r / 255;
267	        cv[i * 3 + 1] = sites[i].g / 255;
268	        cv[i * 3 + 2] = sites[i].b / 255;
269	        mv[i]         = METRIC_INDEX[sites[i].metric];
270	      }
271	      gl.uniform2fv(u.sites,   sv);
272	      gl.uniform3fv(u.colors,  cv);
273	      gl.uniform1iv(u.metrics, mv);
274	    }
275	
276	    gl.drawArrays(gl.TRIANGLES, 0, 6);
277	  }, []);
278	
279	  const renderMarkers = useCallback(() => {
280	    const canvas = markerCanvasRef.current;
281	    if (!canvas) return;
282	    const ctx = canvas.getContext('2d');
283	    if (!ctx) return;
284	
285	    const dpr   = window.devicePixelRatio || 1;
286	    const sites = sitesRef.current;
287	    const selId = selectedIdRef.current;
288	
289	    ctx.clearRect(0, 0, canvas.width, canvas.height);
290	    ctx.save();
291	    ctx.scale(dpr, dpr);
292	
293	    for (const site of sites) {
294	      if (site.id === selId) {
295	        ctx.beginPath();
296	        ctx.arc(site.x, site.y, 11, 0, Math.PI * 2);
297	        ctx.strokeStyle = '#fff';
298	        ctx.lineWidth   = 2.5;
299	        ctx.stroke();
300	        ctx.beginPath();
301	        ctx.arc(site.x, site.y, 11, 0, Math.PI * 2);
302	        ctx.strokeStyle = 'rgba(0,0,0,0.4)';
303	        ctx.lineWidth   = 1;
304	        ctx.stroke();
305	      }
306	
307	      ctx.beginPath();
308	      ctx.arc(site.x, site.y, 6, 0, Math.PI * 2);
309	      ctx.fillStyle = 'rgba(0,0,0,0.45)';
310	      ctx.fill();
311	
312	      ctx.beginPath();
313	      ctx.arc(site.x, site.y, 4, 0, Math.PI * 2);
314	      ctx.fillStyle = '#fff';
315	      ctx.fill();
316	
317	      ctx.font      = 'bold 11px ui-monospace, monospace';
318	      ctx.fillStyle = 'rgba(0,0,0,0.7)';
319	      ctx.fillText(METRIC_LABEL[site.metric], site.x + 9, site.y + 4);
320	    }
321	
322	    ctx.restore();
323	  }, []);
324	
325	  const render = useCallback(() => {
326	    renderGL();
327	    renderMarkers();
328	  }, [renderGL, renderMarkers]);
329	
330	  // ── Resize ──────────────────────────────────────────────────────────────────
331	  const resizeCanvases = useCallback(() => {
332	    const container = containerRef.current;
333	    if (!container) return;
334	    const dpr = window.devicePixelRatio || 1;
335	    const w   = container.clientWidth;
336	    const h   = container.clientHeight;
337	    for (const c of [glCanvasRef.current, markerCanvasRef.current]) {
338	      if (!c) continue;
339	      c.width        = w * dpr;
340	      c.height       = h * dpr;
341	      c.style.width  = `${w}px`;
342	      c.style.height = `${h}px`;
343	    }
344	    render();
345	  }, [render]);
346	
347	  useEffect(() => {
348	    resizeCanvases();
349	    const obs = new ResizeObserver(resizeCanvases);
350	    if (containerRef.current) obs.observe(containerRef.current);
351	    return () => obs.disconnect();
352	  }, [resizeCanvases]);
353	
354	  useEffect(() => {
355	    sitesRef.current = sites;
356	    render();
357	  }, [sites, render]);
358	
359	  // ── Interaction helpers ──────────────────────────────────────────────────────
360	  const getPos = (e: React.MouseEvent) => {
361	    const r = glCanvasRef.current!.getBoundingClientRect();
362	    return { x: e.clientX - r.left, y: e.clientY - r.top };
363	  };
364	
365	  const findNear = (x: number, y: number, r = 14): Site | null => {
366	    let best: Site | null = null, bestD = r;
367	    for (const s of sitesRef.current) {
368	      const d = Math.hypot(s.x - x, s.y - y);
369	      if (d < bestD) { bestD = d; best = s; }
370	    }
371	    return best;
372	  };
373	
374	  // ── Event handlers ───────────────────────────────────────────────────────────
375	  const onMouseDown = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
376	    if (e.button !== 0) return;
377	    const { x, y } = getPos(e);
378	    const near = findNear(x, y);
379	    if (near) {
380	      selectedIdRef.current = near.id;
381	      setSelectedId(near.id);
382	      dragRef.current = { id: near.id, startMouseX: x, startMouseY: y, origX: near.x, origY: near.y, moved: false };
383	      mouseDownOnSite.current = true;
384	      renderMarkers();
385	    } else {
386	      selectedIdRef.current = null;
387	      setSelectedId(null);
388	      mouseDownOnSite.current = false;
389	      dragRef.current = null;
390	      renderMarkers();
391	    }
392	  }, [renderMarkers]);
393	
394	  const onMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
395	    const container = containerRef.current!;
396	    const { x, y } = getPos(e);
397	    setMousePos({ x, y });
398	    setMouseOverCanvas(true);
399	    if (!dragRef.current) {
400	      container.style.cursor = findNear(x, y) ? 'grab' : 'crosshair';
401	      return;
402	    }
403	    const drag = dragRef.current;
404	    const dx = x - drag.startMouseX, dy = y - drag.startMouseY;
405	    if (!drag.moved && (Math.abs(dx) > 3 || Math.abs(dy) > 3)) {
406	      drag.moved = true;
407	      container.style.cursor = 'grabbing';
408	    }
409	    if (!drag.moved) return;
410	    const canvas = glCanvasRef.current!;
411	    const nx = Math.max(0, Math.min(canvas.clientWidth,  drag.origX + dx));
412	    const ny = Math.max(0, Math.min(canvas.clientHeight, drag.origY + dy));
413	    sitesRef.current = sitesRef.current.map(s => s.id === drag.id ? { ...s, x: nx, y: ny } : s);
414	    render();
415	  }, [render]);
416	
417	  const onMouseUp = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
418	    if (e.button !== 0) return;
419	    containerRef.current!.style.cursor = 'crosshair';
420	    if (dragRef.current) {
421	      if (dragRef.current.moved) setSitesState([...sitesRef.current]);
422	      dragRef.current = null;
423	      return;
424	    }
425	    if (!mouseDownOnSite.current) {
426	      const { x, y } = getPos(e);
427	      const hue = (siteCount.current * 137.508) % 360;
428	      const [r, g, b] = hslToRgb(hue, 60, 68);
429	      const id = String(nextId++);
430	      siteCount.current++;
431	      const newSite: Site = { id, x, y, metric: currentMetric, r, g, b };
432	      selectedIdRef.current = id;
433	      setSelectedId(id);
434	      commitSites([...sitesRef.current, newSite]);
435	    }
436	  }, [currentMetric, commitSites]);
437	
438	  const onContextMenu = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
439	    e.preventDefault();
440	    const { x, y } = getPos(e);
441	    const near = findNear(x, y);
442	    if (!near) return;
443	    if (selectedIdRef.current === near.id) { selectedIdRef.current = null; setSelectedId(null); }
444	    commitSites(sitesRef.current.filter(s => s.id !== near.id));
445	  }, [commitSites]);
446	
447	  const applyMetric = useCallback((m: Metric) => {
448	    setCurrentMetric(m);
449	    if (selectedIdRef.current) {
450	      commitSites(sitesRef.current.map(s => s.id === selectedIdRef.current ? { ...s, metric: m } : s));
451	    }
452	  }, [commitSites]);
453	
454	  const activeMetric = selectedId
455	    ? (sites.find(s => s.id === selectedId)?.metric ?? currentMetric)
456	    : currentMetric;
457	
458	  // Per-site distances at the current mouse position, for the toolbar annotation.
459	  const hover = mousePos && sites.length > 0
460	    ? sites.map(s => ({
461	        s,
462	        d: metricDistJS(s.metric, Math.abs(mousePos.x - s.x), Math.abs(mousePos.y - s.y)),
463	      }))
464	    : null;
465	  const hoverMin = hover ? Math.min(...hover.map(h => h.d)) : Infinity;
466	  const showMouseCoordinates = mouseOverCanvas && mousePos;
467	
468	  return (
469	    <div style={{ display: 'flex', flexDirection: 'column', height: '100dvh', background: 'var(--bg)' }}>
470	      {/* ── main toolbar row ── */}
471	      <div style={{
472	        display: 'flex', alignItems: 'center', gap: '0.75rem',
473	        padding: '0.6rem 1rem', borderBottom: '1px solid var(--border)',
474	        fontSize: '0.85rem', fontFamily: 'var(--mono)',
475	      }}>
476	        <a href="/" style={{ color: 'var(--muted)', textDecoration: 'none' }}>←</a>
477	        <span style={{ fontWeight: 'bold' }}>voronoi</span>
478	        <span style={{ color: 'var(--border)' }}>|</span>
479	
480	        {METRICS.map(m => (
481	          <button key={m} onClick={() => applyMetric(m)} title={METRIC_DESC[m]} style={{
482	            background: activeMetric === m ? 'var(--accent)' : 'none',
483	            border:     `1px solid ${activeMetric === m ? 'var(--accent)' : 'var(--border)'}`,
484	            color:      activeMetric === m ? '#fff' : 'var(--fg)',
485	            fontFamily: 'var(--mono)', fontSize: '0.8rem',
486	            padding: '0.15rem 0.55rem', cursor: 'pointer', borderRadius: '2px',
487	          }}>
488	            {METRIC_LABEL[m]}
489	          </button>
490	        ))}
491	
492	        <span style={{ color: 'var(--muted)', fontSize: '0.75rem', marginLeft: 'auto' }}>
493	          {selectedId ? 'drag · change metric · right-click removes' : 'click to place · right-click removes'}
494	        </span>
495	        <button onClick={() => { selectedIdRef.current = null; setSelectedId(null); siteCount.current = 0; commitSites([]); }} style={{
496	          background: 'none', border: '1px solid var(--border)', color: 'var(--muted)',
497	          fontFamily: 'var(--mono)', fontSize: '0.85rem', padding: '0.1rem 0.6rem', cursor: 'pointer',
498	        }}>clear</button>
499	      </div>
500	
501	      {/* ── hover annotation row (always visible for stable layout) ── */}
502	      <div style={{
503	        display: 'grid',
504	        gridTemplateColumns: '6.5rem minmax(0, 1fr)',
505	        columnGap: '0.75rem',
506	        padding: '0 1rem', borderBottom: '1px solid var(--border)',
507	        fontSize: '0.78rem', fontFamily: 'var(--mono)', lineHeight: 1.25,
508	        minHeight: '1.9rem', maxHeight: '6.5rem',
509	        overflowX: 'hidden', overflowY: 'auto',
510	        fontVariantNumeric: 'tabular-nums',
511	      }}>
512	        {hover ? (
513	          <>
514	            {showMouseCoordinates && (
515	              <span style={{ color: 'var(--muted)', whiteSpace: 'nowrap', paddingTop: '0.35rem' }}>
516	                ({Math.round(mousePos!.x)}, {Math.round(mousePos!.y)})
517	              </span>
518	            )}
519	            <div style={{
520	              display: 'grid',
521	              gridColumn: showMouseCoordinates ? undefined : '1 / -1',
522	              gridTemplateColumns: 'repeat(auto-fill, minmax(18rem, 1fr))',
523	              gap: '0.25rem 0.75rem',
524	              minWidth: 0,
525	              padding: '0.25rem 0',
526	            }}>
527	              {hover.map(({ s, d }) => {
528	                const winner = d === hoverMin;
529	                const dx = Math.abs(mousePos!.x - s.x);
530	                const dy = Math.abs(mousePos!.y - s.y);
531	                const calculation = metricCalculation(s.metric, dx, dy);
532	                return (
533	                  <span key={s.id} title={`dx=${fmt(dx)}, dy=${fmt(dy)}; ${METRIC_LABEL[s.metric]}: ${METRIC_FORMULA[s.metric]}`} style={{
534	                    display: 'inline-flex', alignItems: 'center', gap: '0.25rem',
535	                    minWidth: 0,
536	                    color: winner ? 'var(--fg)' : 'var(--muted)',
537	                    fontWeight: winner ? 'bold' : 'normal',
538	                    whiteSpace: 'nowrap',
539	                    overflow: 'hidden',
540	                    textOverflow: 'ellipsis',
541	                  }}>
542	                    <span style={{
543	                      display: 'inline-block', width: '7px', height: '7px',
544	                      borderRadius: '50%', flexShrink: 0,
545	                      background: `rgb(${s.r},${s.g},${s.b})`,
546	                      boxShadow: winner ? '0 0 0 1.5px var(--fg)' : 'none',
547	                    }} />
548	                    <span style={{ color: 'var(--muted)', fontSize: '0.72rem', flexShrink: 0 }}>{METRIC_LABEL[s.metric]}</span>
549	                    <span style={{ overflow: 'hidden', textOverflow: 'ellipsis' }}>{calculation}</span>
550	                    {winner && <span style={{ color: 'var(--accent)', flexShrink: 0 }}>◀</span>}
551	                  </span>
552	                );
553	              })}
554	            </div>
555	          </>
556	        ) : (
557	          <>
558	            <div style={{
559	              display: 'grid',
560	              gridColumn: '1 / -1',
561	              gridTemplateColumns: 'repeat(auto-fill, minmax(18rem, 1fr))',
562	              gap: '0.25rem 0.75rem',
563	              minWidth: 0,
564	              padding: '0.25rem 0',
565	            }}>
566	              {METRICS.map(m => (
567	                <span key={m} title={`${METRIC_DESC[m]}: ${METRIC_GENERIC_CALC[m]}`} style={{
568	                  display: 'inline-flex', alignItems: 'center', gap: '0.25rem',
569	                  minWidth: 0,
570	                  color: 'var(--muted)',
571	                  whiteSpace: 'nowrap',
572	                  overflow: 'hidden',
573	                  textOverflow: 'ellipsis',
574	                }}>
575	                  <span style={{ color: 'var(--muted)', fontSize: '0.72rem', flexShrink: 0 }}>{METRIC_LABEL[m]}</span>
576	                  <span style={{ overflow: 'hidden', textOverflow: 'ellipsis' }}>{METRIC_GENERIC_CALC[m]}</span>
577	                </span>
578	              ))}
579	            </div>
580	          </>
581	        )}
582	      </div>
583	
584	      <div
585	        ref={containerRef}
586	        style={{ flex: 1, overflow: 'hidden', position: 'relative', cursor: 'crosshair' }}
587	        onMouseDown={onMouseDown}
588	        onMouseMove={onMouseMove}
589	        onMouseUp={onMouseUp}
590	        onMouseLeave={() => setMouseOverCanvas(false)}
591	        onContextMenu={onContextMenu}
592	      >
593	        {/* WebGL canvas: Voronoi cells at full physical resolution */}
594	        <canvas ref={glCanvasRef} style={{ position: 'absolute', inset: 0, display: 'block' }} />
595	        {/* 2D canvas: site markers (transparent, non-interactive) */}
596	        <canvas ref={markerCanvasRef} style={{ position: 'absolute', inset: 0, display: 'block', pointerEvents: 'none' }} />
597	
598	        {sites.length === 0 && (
599	          <div style={{
600	            position: 'absolute', inset: 0,
601	            display: 'flex', alignItems: 'center', justifyContent: 'center',
602	            flexDirection: 'column', gap: '0.4rem',
603	            color: 'var(--muted)', fontFamily: 'var(--mono)', pointerEvents: 'none',
604	          }}>
605	            <span>click to place points</span>
606	            <span style={{ fontSize: '0.75rem' }}>each point uses its own distance metric</span>
607	          </div>
608	        )}
609	      </div>
610	    </div>
611	  );
