          ? `dx=${fmt(Math.abs(mousePos!.x - s.x))}, dy=${fmt(Math.abs(mousePos!.y - s.y))}; ${METRIC_LABEL[s.metric]}: ${METRIC_FORMULA[s.metric]}`
